module top_module(
    input [7:0] A,
    input [7:0] B,
    output [7:0] sum,
    output carry_out
);wire [8:0] unused_temp_sum;

    // Add A and B, store result in unused_temp_sum
    assign unused_temp_sum = {1'b0, A} + {1'b0, B};

    // Assign sum to the 8 least significant bits of unused_temp_sum
    assign sum = unused_temp_sum[7:0];

    // Assign carry_out to the most significant bit of unused_temp_sum
    assign carry_out = unused_temp_sum[8];

endmodule
